script:
export const meta = {
  name: 'pass10-assess',
  description: 'Pass-10 adversarial assessment: actual-CI-execution + pass-9 fix-regression + standing dims',
  phases: [{ title: 'Assess' }, { title: 'Refute' }],
}
const REPO = '/Users/[REDACTED]/hc-assay'
const FINDINGS_SCHEMA = {
  type: 'object', additionalProperties: false, required: ['findings'],
  properties: { findings: { type: 'array', items: {
    type: 'object', additionalProperties: false,
    required: ['id', 'severity', 'title', 'location', 'claim', 'why_real', 'suggested_fix'],
    properties: {
      id: { type: 'string' }, severity: { type: 'string', enum: ['critical', 'high', 'medium', 'low'] },
      title: { type: 'string' }, location: { type: 'string' }, claim: { type: 'string' },
      why_real: { type: 'string' }, suggested_fix: { type: 'string' },
    },
  } } },
}
const COMMON = `You are an adversarial production-readiness assessor for the hc-assay engine at ${REPO} (dataset-agnostic, data-sovereign empirical-ML/methodology engine; optional backends import-guarded; transcripts committed + scrubbed intentionally). It has survived NINE hardening passes and CI is green — easy findings are gone. Report ONLY genuine, concrete, FALSIFIABLE production-readiness defects with a real failure mode and a file:line/symbol location; no style nits. If a dimension is clean, return few/zero findings — do NOT invent. Read real code (Read/Grep/Bash; "python -m pytest", "source .venv/bin/activate"; gh for CI). Branch harden/pass-10 (from merged main @ pass 9).`
const DIMENSIONS = [
  { key: 'FIXREG9', label: 'pass-9 fix-regression audit (priority)', focus: `Audit pass-9's OWN changes for follow-on defects (git log main; the K-SEC-9-1, CI-1, P9-PII-1, P9-MO-1, P9-MO-2 fixes). Scrutinize: (1) _local.py multi-host split — does splitting on "," interact badly with quoted values, IPv6 (which contains colons not commas, but bracketed?), an empty element ("host=/tmp,"), or a hostaddr list? Could a value like "host=localhost ,evil.com" (space) or percent-encoding evade it? Does is_local_socket_path rejecting comma break a legit socket dir literally containing a comma (rare)? (2) _hostname_patterns — the machine-hostname rule redacts bare name + .local with \\b; could a short/common derived hostname (e.g. a CI runner "fv-az..." or "localhost") over-redact legit content, or could socket.gethostname() return something that breaks the regex? Is _HOSTNAME_RES computed at import a problem if env changes? (3) _envparse int_env/float_env — empty-string-as-default change: did it alter any existing behavior (e.g. a var legitimately set to "0")? does float_env accept "inf"/"nan" (and should it)? (4) require_green_ci.sh — the confirm noted it checks latest run conclusion NOT headSha, so a stale green run from an earlier commit passes the gate while a new push has no completed run yet; is that a real merge-safety hole? (5) _validate_alpha None branch — any caller now passing None that previously worked?` },
  { key: 'CIEXEC', label: 'actual CI execution', focus: `Inspect the REAL CI (gh run list/view --branch main; read ci.yml). Reproduce each lane's EXACT command (bare pytest; no-extras core lane; cold uv resolve; matrix 3.11-3.14). Find: tests importing optional backends without pytest.importorskip that fail the core lane; any gate that passes vacuously or fails nondeterministically; the lockfile --exclude-newer determinism (could a NEW in-range release before the 2026-06-14 cutoff still flip resolution?); coverage floor correctness; the require_green_ci.sh stale-run hole as a CI finding. Confirm main CI is actually green and STAYS green.` },
  { key: 'PRIV', label: 'privacy/PII', focus: `Re-probe scripts/capture_transcripts.py + committed corpus for any remaining operator-identity vector or new secret/PII class (other hostnames, IPs like 192.168.x, internal URLs, tokens, the new _envparse/_local/scripts files, MERGE-POLICY.md). The handle/name/username/email/hostname classes are covered — look for something NEW.` },
  { key: 'SEC', label: 'security/data-sovereignty', focus: `Local-URI guards across ALL backends (re-audit _local.py after the multi-host split for any remaining bypass: IPv6 zone-id, percent-encoding, trailing dot, uppercase LOCALHOST, "0.0.0.0", DNS-rebinding-style names), injection, unsafe deserialization (pickle/yaml), path traversal, SSRF, secret handling/logging.` },
  { key: 'CONC', label: 'correctness/concurrency/reliability', focus: `Races, the reasoning thread pool, cancellation/timeout, resource leaks (fds/connections/subprocesses/threads), partial-failure, retry/backoff, run_study idempotency, the MLflow lifecycle, signal-handler re-entrancy (the pass-8 SIGTERM re-delivery).` },
  { key: 'METHOBS', label: 'methodology integrity + observability/provenance', focus: `Pre-registration firewall/HARKing prevention, canonical_hypothesis_digest binding, confirm primitives (alpha/stability resolution, the new None branch), provenance trail integrity (append-only/keyed/tamper-evident), structured logging not leaking secrets, env parsing.` },
]
phase('Assess')
const refuteSchema = { type: 'object', additionalProperties: false, required: ['verdict', 'reasoning'], properties: { verdict: { type: 'string', enum: ['STANDS', 'REFUTED'] }, reasoning: { type: 'string' } } }
const perDim = await parallel(DIMENSIONS.map((d) => () =>
  agent(`${COMMON}\n\nYOUR DIMENSION: ${d.label}.\n${d.focus}`, { label: `assess:${d.key}`, phase: 'Assess', schema: FINDINGS_SCHEMA }).then((r) => ({ dim: d.key, findings: (r && r.findings) || [] }))
))
const all = perDim.filter(Boolean).flatMap((r) => r.findings.map((f) => ({ ...f, dim: r.dim })))
log(`Assess: ${all.length} raw findings`)
phase('Refute')
const judged = await parallel(all.map((f) => () =>
  agent(`You are an adversarial skeptic. Try to REFUTE this pass-10 finding about ${REPO} by reading the actual code. REFUTED if false, already-mitigated, out-of-scope by design (dataset-agnostic engine, optional import-guarded backends, intentionally-committed scrubbed transcripts, on-box data-sovereignty, documented honest-scope), or not a real production defect. Default to REFUTED if it doesn't hold. Use python/pytest/gh as needed.\n\nFINDING ${f.id} (${f.severity}, ${f.dim}): ${f.title}\nLocation: ${f.location}\nClaim: ${f.claim}\nWhy real: ${f.why_real}`,
    { label: `refute:${f.id}`, phase: 'Refute', schema: refuteSchema }).then((v) => ({ ...f, refute: v }))
))
const survivors = judged.filter(Boolean).filter((f) => f.refute && f.refute.verdict === 'STANDS')
const refuted = judged.filter(Boolean).filter((f) => !f.refute || f.refute.verdict === 'REFUTED')
log(`Self-refutation: ${survivors.length} STAND, ${refuted.length} refuted`)
const bySev = (a) => ['critical', 'high', 'medium', 'low'].map((s) => `${s}:${a.filter((f) => f.severity === s).length}`).join(' ')
log(`Survivors — ${bySev(survivors)}`)
return { survivors, refuted_ids: refuted.map((f) => ({ id: f.id, dim: f.dim, why: f.refute && f.refute.reasoning })) }
